namespace Zuke.Core.Numbering; public static class JapaneseNumberFormatter { public static string ToArticle(int n,bool arabic)=> arabic? $"第{n}条" : $"第{n}条"; public static string ToParagraphNum(int n)=>n==1?"":n.ToString().Replace("0","０").Replace("1","１").Replace("2","２").Replace("3","３").Replace("4","４").Replace("5","５").Replace("6","６").Replace("7","７").Replace("8","８").Replace("9","９");}
